use anyhow::Result;
use serenity::all::{Channel, CreateMessage};
use serenity::builder::CreateAttachment;
use serenity::model::channel::Message;
use serenity::prelude::*;
use std::time::Duration;
use tracing::{error, info};

pub async fn handle_imagine_command(
    ctx: &Context,
    msg: &Message,
    prompt: &str,
    imagine_channels: &[String],
) -> Result<()> {
    // Check if the command is being used in an allowed channel
    let channel_name = match msg.channel_id.to_channel(&ctx.http).await {
        Ok(channel) => match channel {
            Channel::Guild(guild_channel) => guild_channel.name,
            _ => String::new(),
        },
        Err(_) => String::new(),
    };

    if !imagine_channels.is_empty() && !imagine_channels.contains(&channel_name) {
        let channel_list = if imagine_channels.len() == 1 {
            format!("the #{} channel", imagine_channels[0])
        } else {
            let channels = imagine_channels
                .iter()
                .map(|c| format!("#{c}"))
                .collect::<Vec<_>>()
                .join(", ");
            format!("one of these channels: {channels}")
        };
        msg.reply(
            &ctx.http,
            format!("Image generation is only available in {channel_list}. Please try your command there."),
        )
        .await?;
        return Ok(());
    }

    // Start typing indicator
    if let Err(e) = msg.channel_id.broadcast_typing(&ctx.http).await {
        error!(
            "Failed to send typing indicator for image generation: {:?}",
            e
        );
    }

    info!("Generating image via Pollinations for prompt: {}", prompt);

    let encoded_prompt = urlencoding::encode(prompt);
    let url = format!(
        "https://image.pollinations.ai/prompt/{encoded_prompt}?width=1024&height=1024&nologo=true"
    );

    let client = reqwest::Client::new();
    let response = client
        .get(&url)
        .timeout(Duration::from_secs(60))
        .send()
        .await;

    match response {
        Ok(resp) if resp.status().is_success() => {
            let image_bytes = resp.bytes().await?;

            let temp_dir = std::env::temp_dir();
            let file_path = temp_dir.join(format!(
                "pollinations_image_{}.png",
                chrono::Utc::now().timestamp()
            ));
            std::fs::write(&file_path, &image_bytes)?;

            let files = vec![CreateAttachment::path(&file_path).await?];
            let message_content = format!("Here's what I imagine for: {prompt}");
            let builder = files
                .into_iter()
                .fold(CreateMessage::default().content(message_content), |b, f| {
                    b.add_file(f)
                });

            if let Err(e) = msg.channel_id.send_message(&ctx.http, builder).await {
                error!("Failed to send generated image: {:?}", e);
                msg.reply(&ctx.http, "Sorry, I couldn't send the generated image.")
                    .await?;
            }

            if let Err(e) = std::fs::remove_file(file_path) {
                error!("Failed to clean up temporary image file: {:?}", e);
            }
        }
        Ok(resp) => {
            error!("Pollinations API error: HTTP {}", resp.status());
            msg.reply(
                &ctx.http,
                "Sorry, I couldn't generate that image. Please try again.",
            )
            .await?;
        }
        Err(e) => {
            error!("Pollinations API request failed: {:?}", e);
            msg.reply(
                &ctx.http,
                "Sorry, image generation timed out. Please try again.",
            )
            .await?;
        }
    }

    Ok(())
}

use crate::prompt_templates::PromptTemplates;
use crate::rate_limiter::RateLimiter;
use anyhow::Result;
use chrono::{DateTime, Utc};
use rand::RngExt;
use std::collections::HashMap;
use std::sync::Arc;
use std::time::Duration;
use tokio::sync::Mutex;
use tracing::{error, info};

#[derive(Clone)]
pub struct GeminiClient {
    api_key: String,
    api_endpoint: String,
    prompt_templates: PromptTemplates,
    rate_limiter: RateLimiter,
    image_rate_limiter: RateLimiter,
    #[allow(dead_code)]
    context_messages: usize,
    log_prompts: bool,
    // Track when image generation quota was exhausted
    image_quota_exhausted_until: Arc<Mutex<Option<DateTime<Utc>>>>,
}

/// Configuration for creating a GeminiClient
#[derive(Debug, Clone)]
pub struct GeminiConfig {
    pub api_key: String,
    pub api_endpoint: Option<String>,
    pub prompt_wrapper: Option<String>,
    pub bot_name: String,
    pub rate_limit_minute: u32,
    pub rate_limit_day: u32,
    pub image_rate_limit_minute: u32,
    pub image_rate_limit_day: u32,
    pub context_messages: usize,
    pub log_prompts: bool,
    pub personality_description: Option<String>,
}

impl GeminiClient {
    pub fn new(config: GeminiConfig) -> Self {
        // Default endpoint for Gemini API
        let default_endpoint = "https://generativelanguage.googleapis.com/v1beta/models/gemini-3.1-flash-lite-preview:generateContent".to_string();

        // Create prompt templates with custom personality if provided
        let mut prompt_templates = PromptTemplates::new_with_custom_personality(
            config.bot_name.clone(),
            config.personality_description,
        );

        // If a custom prompt wrapper is provided, set it as the general response template
        if let Some(wrapper) = config.prompt_wrapper {
            prompt_templates.set_template("general_response", &wrapper);
        }

        // Create rate limiter for text generation with persistence
        let rate_limiter = RateLimiter::new_with_persistence(
            config.rate_limit_minute,
            config.rate_limit_day,
            "gemini_text_quota.json".to_string(),
        );

        // Create separate rate limiter for image generation with persistence
        let image_rate_limiter = RateLimiter::new_with_persistence(
            config.image_rate_limit_minute,
            config.image_rate_limit_day,
            "gemini_image_quota.json".to_string(),
        );

        Self {
            api_key: config.api_key,
            api_endpoint: config.api_endpoint.unwrap_or(default_endpoint),
            prompt_templates,
            rate_limiter,
            image_rate_limiter,
            context_messages: config.context_messages,
            log_prompts: config.log_prompts,
            image_quota_exhausted_until: Arc::new(Mutex::new(None)),
        }
    }

    /// Get API quota usage statistics
    pub async fn get_quota_stats(&self) -> (String, String, String) {
        // Get text API usage
        let (text_min_used, text_min_limit, text_day_used, text_day_limit) =
            self.rate_limiter.get_usage_stats().await;
        let text_quota = format!(
            "{}/{} per minute, {}/{} per day",
            text_min_used, text_min_limit, text_day_used, text_day_limit
        );

        // Get image API usage
        let (img_min_used, img_min_limit, img_day_used, img_day_limit) =
            self.image_rate_limiter.get_usage_stats().await;
        let image_quota = format!(
            "{}/{} per minute, {}/{} per day",
            img_min_used, img_min_limit, img_day_used, img_day_limit
        );

        // Get image quota exhaustion status
        let image_status = if self.is_image_quota_exhausted().await {
            let quota_lock = self.image_quota_exhausted_until.lock().await;
            if let Some(exhausted_until) = *quota_lock {
                format!(
                    "Exhausted until {}",
                    exhausted_until.format("%Y-%m-%d %H:%M UTC")
                )
            } else {
                "Exhausted".to_string()
            }
        } else {
            "Available".to_string()
        };

        (text_quota, image_quota, image_status)
    }

    // Check if image generation is currently blocked due to quota exhaustion
    pub async fn is_image_quota_exhausted(&self) -> bool {
        let quota_lock = self.image_quota_exhausted_until.lock().await;
        if let Some(exhausted_until) = *quota_lock {
            let now = Utc::now();
            if now < exhausted_until {
                return true;
            }
        }
        false
    }

    // Get a reference to the prompt templates
    pub fn prompt_templates(&self) -> &PromptTemplates {
        &self.prompt_templates
    }

    // Get a mutable reference to the prompt templates
    #[allow(dead_code)]
    pub fn prompt_templates_mut(&mut self) -> &mut PromptTemplates {
        &mut self.prompt_templates
    }

    // Generate a response with conversation context
    pub async fn generate_response_with_context(
        &self,
        prompt: &str,
        user_name: &str,
        context_messages: &[(String, String, String)],
        user_pronouns: Option<&str>,
    ) -> Result<String> {
        // Convert to the new format with pronouns
        let context_with_pronouns: Vec<(String, String, Option<String>, String)> = context_messages
            .iter()
            .map(|(author, display_name, content)| {
                let pronouns = crate::utils::extract_pronouns(display_name);
                (
                    author.clone(),
                    display_name.clone(),
                    pronouns,
                    content.clone(),
                )
            })
            .collect();

        self.generate_response_with_context_and_pronouns(
            prompt,
            user_name,
            &context_with_pronouns,
            user_pronouns,
        )
        .await
    }

    // Generate multiple responses with context and select one randomly
    pub async fn generate_best_response_with_context_and_pronouns(
        &self,
        prompt: &str,
        user_name: &str,
        context_messages: &[(String, String, Option<String>, String)],
        user_pronouns: Option<&str>,
        should_respond: bool,
    ) -> Result<Option<String>> {
        // Create a modified prompt that asks for multiple responses
        let multi_response_prompt = format!(
            "{}\n\nIMPORTANT: You are responding to {user_name}. Do not address anyone else by name unless directly relevant to your response.\n\nGenerate exactly 3-5 different response options, each on a separate line starting with 'OPTION:'. Make each response unique in tone and approach while staying in character. Make your responses about 10% funnier than usual - add wit, unexpected turns, or clever observations. If you decide not to respond at all, just respond with 'PASS'.",
            prompt
        );

        match self
            .generate_response_with_context_and_pronouns(
                &multi_response_prompt,
                user_name,
                context_messages,
                user_pronouns,
            )
            .await
        {
            Ok(response) => {
                let trimmed = response.trim();

                // Check if the AI decided to pass
                if trimmed.to_lowercase() == "pass" {
                    return Ok(None);
                }

                // Parse the response options
                let options: Vec<String> = trimmed
                    .lines()
                    .filter_map(|line| {
                        let line = line.trim();
                        if line.starts_with("OPTION:") {
                            let option = line.strip_prefix("OPTION:").unwrap_or(line).trim();
                            if !option.is_empty() && option.to_lowercase() != "pass" {
                                Some(option.to_string())
                            } else {
                                None
                            }
                        } else {
                            None
                        }
                    })
                    .collect();

                if options.is_empty() {
                    // Fallback: use the original response if no options were parsed
                    if should_respond {
                        Ok(Some(trimmed.to_string()))
                    } else {
                        Ok(None)
                    }
                } else {
                    // Weighted selection: option #2 = 75%, option #3 = 15%, rest split remaining 10%
                    let rand_val = rand::rng().random_range(0.0..1.0);
                    let selected_idx = if options.len() >= 2 && rand_val < 0.75 {
                        // 75% chance: select option #2 (index 1)
                        1
                    } else if options.len() >= 3 && rand_val < 0.90 {
                        // 15% chance: select option #3 (index 2)
                        2
                    } else {
                        // 10% chance: select from remaining options (excluding #2 and #3)
                        let remaining: Vec<usize> =
                            (0..options.len()).filter(|&i| i != 1 && i != 2).collect();
                        if remaining.is_empty() {
                            // Fallback if only 1-2 options exist
                            rand::rng().random_range(0..options.len())
                        } else {
                            remaining[rand::rng().random_range(0..remaining.len())]
                        }
                    };

                    let selected = &options[selected_idx];
                    if should_respond {
                        Ok(Some(selected.clone()))
                    } else {
                        Ok(None)
                    }
                }
            }
            Err(e) => Err(e),
        }
    }

    // New function that accepts context messages with pronouns
    pub async fn generate_response_with_context_and_pronouns(
        &self,
        prompt: &str,
        user_name: &str,
        context_messages: &[(String, String, Option<String>, String)],
        _user_pronouns: Option<&str>,
    ) -> Result<String> {
        // Check if the prompt already contains context (like in interjection prompts)
        let has_context_in_prompt = prompt.contains("{context}");

        // Format the context messages
        let context = if !context_messages.is_empty() {
            // Get the messages in chronological order (oldest first)
            // The database query returns newest first, so we need to reverse
            let mut chronological_messages = context_messages.to_owned();
            chronological_messages.reverse();

            // Format each message as "DisplayName (pronouns): Message" using the display_name field
            // If display_name is empty, fall back to author name
            let formatted_messages = chronological_messages
                .iter()
                .map(|(author, display_name, pronouns, msg)| {
                    let name_to_use = if !display_name.is_empty() {
                        display_name
                    } else {
                        author
                    };

                    // Include pronouns if available
                    if let Some(pronouns) = pronouns {
                        format!("{name_to_use} ({pronouns}): {msg}")
                    } else {
                        format!("{name_to_use}: {msg}")
                    }
                })
                .collect::<Vec<_>>()
                .join("\n");

            info!(
                "Using context for response generation: {} messages",
                context_messages.len()
            );
            formatted_messages
        } else if has_context_in_prompt {
            // If the prompt already contains context placeholder but we have no messages,
            // use an empty string to avoid adding "No context available"
            info!("No database context available, but prompt contains context placeholder");
            "".to_string()
        } else {
            info!(
                "No context available for response generation to user: {}",
                user_name
            );
            "No context available.".to_string()
        };

        // Format the prompt using the wrapper or custom template
        let formatted_prompt = if has_context_in_prompt {
            // If the prompt already contains {context}, use it as a custom template
            let mut values = HashMap::new();
            values.insert("context".to_string(), context);
            self.prompt_templates.format_custom(prompt, &values)
        } else {
            // Otherwise use the standard general response template
            self.prompt_templates
                .format_general_response(prompt, user_name, &context)
        };

        self.generate_content(&formatted_prompt).await
    }

    // Generate content with a raw prompt and retry on overload errors.
    // Automatically detects image/video URLs in context and upgrades to multimodal.
    pub async fn generate_content(&self, prompt: &str) -> Result<String> {
        // Check if the prompt contains embedded media URLs from context
        let context_media = crate::media_utils::fetch_media_from_context(prompt, 3).await;

        if !context_media.is_empty() {
            info!(
                "Auto-upgrading to multimodal: found {} media items in context",
                context_media.len()
            );
            let clean_prompt = crate::media_utils::strip_media_urls_from_context(prompt);
            return self
                .generate_content_with_media(&clean_prompt, &context_media, &[])
                .await;
        }

        self.generate_content_text_only(prompt).await
    }

    // Text-only content generation with retry on overload errors
    async fn generate_content_text_only(&self, prompt: &str) -> Result<String> {
        // Maximum number of retries
        const MAX_RETRIES: usize = 5;

        // Initial delay in seconds (will be doubled each retry - exponential backoff)
        let mut delay_secs = 10;

        // Try up to MAX_RETRIES times
        for attempt in 1..=MAX_RETRIES {
            // Use acquire() which includes retry logic and request recording
            self.rate_limiter.acquire().await?;

            // Log the prompt if enabled
            if self.log_prompts {
                info!("Gemini API Prompt: {}", prompt);
            }

            // Prepare the request body
            let request_body = serde_json::json!({
                "contents": [{
                    "parts": [{
                        "text": prompt
                    }]
                }]
            });

            // Build the URL with API key
            let url = format!("{}?key={}", self.api_endpoint, self.api_key);

            // Make the API call
            let client = reqwest::Client::new();
            let response = client
                .post(&url)
                .json(&request_body)
                .timeout(Duration::from_secs(30))
                .send()
                .await?;

            // Parse the response
            let response_json: serde_json::Value = response.json().await?;

            // Log the full raw response if logging is enabled
            if self.log_prompts {
                if let Ok(pretty_json) = serde_json::to_string_pretty(&response_json) {
                    info!("Gemini API Raw Response: {}", pretty_json);
                } else {
                    info!("Gemini API Raw Response: {}", response_json);
                }
            }

            // Check for error in response
            if let Some(error) = response_json.get("error") {
                let error_message = error
                    .get("message")
                    .and_then(|m| m.as_str())
                    .unwrap_or("Unknown API error");
                let error_code = error.get("code").and_then(|c| c.as_u64()).unwrap_or(0);

                // Check for billing/spending cap errors - return a friendly message
                if error_message.contains("spending cap")
                    || error_message.contains("BillingHardLimit")
                {
                    error!(
                        "Gemini API billing error (code {}): {}",
                        error_code, error_message
                    );
                    return Err(anyhow::anyhow!(
                        "BILLING_ERROR: The Gemini API quota or billing limit has been reached. The bot will continue working once the limit resets."
                    ));
                }

                // Check if this is a retryable error
                if error_message.contains("overloaded")
                    || error_message.contains("try again later")
                    || (error_code == 500 && error_message.contains("Internal error encountered"))
                {
                    if attempt < MAX_RETRIES {
                        // Log that we're retrying
                        info!(
                            "Gemini API retryable error (attempt {}/{}): {} (code {}), retrying in {} seconds...",
                            attempt, MAX_RETRIES, error_message, error_code, delay_secs
                        );

                        // Wait before retrying
                        tokio::time::sleep(Duration::from_secs(delay_secs)).await;

                        // Double the delay for next attempt (exponential backoff)
                        delay_secs *= 2;

                        // Continue to the next retry attempt
                        continue;
                    } else {
                        // If we've exhausted retries, return a special error
                        // that callers can check for to avoid showing error messages to users
                        error!(
                            "Gemini API retryable error, maximum retries ({}) exceeded: {} (code {})",
                            MAX_RETRIES, error_message, error_code
                        );
                        return Err(anyhow::anyhow!(
                            "SILENT_ERROR: Gemini API retryable error after {} retries: {}",
                            MAX_RETRIES,
                            error_message
                        ));
                    }
                }

                // If it's not a retryable error, return the error
                error!("Gemini API error (code {}): {}", error_code, error_message);
                return Err(anyhow::anyhow!("Gemini API error: {}", error_message));
            }

            // Check for finish reason
            if let Some(candidates) = response_json.get("candidates") {
                if let Some(candidate) = candidates.get(0) {
                    if let Some(finish_reason) = candidate.get("finishReason") {
                        if finish_reason != "STOP" {
                            let reason = finish_reason.as_str().unwrap_or("UNKNOWN");
                            error!("Gemini API response has non-STOP finish reason: {}", reason);
                            if reason == "SAFETY" {
                                return Err(anyhow::anyhow!("Gemini API safety filters triggered. The prompt may contain inappropriate content."));
                            } else if reason == "RECITATION" {
                                return Err(anyhow::anyhow!("Gemini API detected content recitation. The response may contain copied content."));
                            } else if reason == "OTHER" {
                                return Err(anyhow::anyhow!(
                                    "Gemini API terminated the response for an unspecified reason."
                                ));
                            }
                        }
                    }
                }
            }

            // Extract the generated text
            if let Some(text) = response_json
                .get("candidates")
                .and_then(|c| c.get(0))
                .and_then(|c| c.get("content"))
                .and_then(|c| c.get("parts"))
                .and_then(|p| p.get(0))
                .and_then(|p| p.get("text"))
                .and_then(|t| t.as_str())
            {
                // Log the response if enabled
                if self.log_prompts {
                    info!("Gemini API Response Text: {}", text);
                } else {
                    info!("Successfully generated content from Gemini API");
                }

                // Strip surrounding quotes if present
                let cleaned_text =
                    if text.starts_with('"') && text.ends_with('"') && text.len() >= 2 {
                        // Remove the first and last character (the quotes)
                        &text[1..text.len() - 1]
                    } else {
                        text
                    };

                // Success! Return the text
                return Ok(cleaned_text.to_string());
            } else {
                // Check for prompt feedback
                let prompt_feedback = if let Some(feedback) = response_json.get("promptFeedback") {
                    if let Some(block_reason) = feedback.get("blockReason") {
                        let block_reason_str = block_reason.as_str().unwrap_or("UNKNOWN");
                        format!("Prompt blocked: {block_reason_str}")
                    } else {
                        "Prompt feedback present but no block reason specified".to_string()
                    }
                } else {
                    "No prompt feedback available".to_string()
                };

                error!(
                    "Failed to extract text from Gemini API response: {}",
                    prompt_feedback
                );
                return Err(anyhow::anyhow!(
                    "Failed to extract text from Gemini API response: {}",
                    prompt_feedback
                ));
            }
        }

        // This should never be reached due to the return statements above,
        // but we need it for the compiler
        Err(anyhow::anyhow!("Maximum retry attempts exceeded"))
    }

    /// Generate content with text and media (images/video) using multimodal input
    pub async fn generate_content_with_media(
        &self,
        prompt: &str,
        media: &[crate::media_utils::MediaItem],
        youtube_urls: &[crate::media_utils::YouTubeUrl],
    ) -> Result<String> {
        if media.is_empty() && youtube_urls.is_empty() {
            return self.generate_content_text_only(prompt).await;
        }

        self.rate_limiter.acquire().await?;

        if self.log_prompts {
            info!(
                "Gemini API Multimodal Prompt: {} ({} media items, {} YouTube URLs)",
                prompt,
                media.len(),
                youtube_urls.len()
            );
        }

        // Build parts array: media first, then text
        let mut parts = Vec::new();

        for item in media {
            parts.push(serde_json::json!({
                "inline_data": {
                    "mime_type": item.mime_type,
                    "data": item.data
                }
            }));
        }

        for yt in youtube_urls {
            parts.push(serde_json::json!({
                "file_data": {
                    "mime_type": "video/*",
                    "file_uri": yt.url
                }
            }));
        }

        parts.push(serde_json::json!({"text": prompt}));

        let request_body = serde_json::json!({
            "contents": [{"parts": parts}]
        });

        let url = format!("{}?key={}", self.api_endpoint, self.api_key);
        let client = reqwest::Client::new();
        let response = client
            .post(&url)
            .json(&request_body)
            .timeout(Duration::from_secs(60)) // longer timeout for media
            .send()
            .await?;

        let response_json: serde_json::Value = response.json().await?;

        if self.log_prompts {
            if let Ok(pretty) = serde_json::to_string_pretty(&response_json) {
                info!("Gemini API Multimodal Response: {}", pretty);
            }
        }

        // Check for errors
        if let Some(error) = response_json.get("error") {
            let msg = error
                .get("message")
                .and_then(|m| m.as_str())
                .unwrap_or("Unknown API error");
            // Check for billing/spending cap errors
            if msg.contains("spending cap") || msg.contains("BillingHardLimit") {
                error!("Gemini multimodal API billing error: {}", msg);
                return Err(anyhow::anyhow!(
                    "BILLING_ERROR: The Gemini API quota or billing limit has been reached. The bot will continue working once the limit resets."
                ));
            }
            error!("Gemini multimodal API error: {}", msg);
            return Err(anyhow::anyhow!("Gemini API error: {}", msg));
        }

        // Extract text from response
        if let Some(text) = response_json
            .pointer("/candidates/0/content/parts/0/text")
            .and_then(|t| t.as_str())
        {
            Ok(text.to_string())
        } else {
            Err(anyhow::anyhow!(
                "Failed to extract text from multimodal response"
            ))
        }
    }
}

