# Quick test: can Gemini 2.5 Flash generate images via responseModalities?
# Usage: ./test_gemini_image.sh YOUR_API_KEY

API_KEY="${1:?Usage: ./test_gemini_image.sh YOUR_GEMINI_API_KEY}"

echo "Testing Gemini 2.5 Flash with image output..."
curl -s -X POST \
  "https://generativelanguage.googleapis.com/v1beta/models/gemini-2.5-flash:generateContent?key=${API_KEY}" \
  -H "Content-Type: application/json" \
  -d '{
    "contents": [{"parts": [{"text": "Generate a simple image of a black crow sitting on a fence post"}]}],
    "generationConfig": {"responseModalities": ["image", "text"]}
  }' | python3 -c '
import sys, json
data = json.load(sys.stdin)
if "error" in data:
    print(f"ERROR: {data[\"error\"][\"message\"]}")
    print(f"Code:  {data[\"error\"].get(\"code\", \"unknown\")}")
elif "candidates" in data:
    parts = data["candidates"][0]["content"]["parts"]
    for p in parts:
        if "inlineData" in p:
            mime = p["inlineData"]["mimeType"]
            size = len(p["inlineData"]["data"])
            print(f"SUCCESS! Got image: {mime}, ~{size // 1024}KB base64")
        elif "text" in p:
            print(f"Text: {p[\"text'][:200]}")
else:
    print("Unexpected response:")
    print(json.dumps(data, indent=2)[:500])
'

