#!/usr/bin/env python3
"""Test which Gemini models support image generation on your API key."""
import sys, json, urllib.request, urllib.error

API_KEY = sys.argv[1] if len(sys.argv) > 1 else sys.exit("Usage: python3 test_models.py YOUR_API_KEY")

BASE = "https://generativelanguage.googleapis.com/v1beta/models"

MODELS = [
    "gemini-2.5-flash",
    "gemini-2.5-flash-lite",
    "gemini-3.0-flash",
    "gemini-3.1-flash-lite",
    "gemini-2.5-flash-preview-image-generation",
    "gemini-2.5-flash-exp-image-generation",
    "gemini-2.0-flash",
    "gemini-2.0-flash-lite",
    "gemini-2.5-pro",
    "imagen-4.0-generate-001",
    "imagen-4.0-fast-generate-001",
    "imagen-4.0-ultra-generate-001",
    "imagen-3.0-generate-002",
    "imagen-3.0-fast-generate-001",
]

prompt_payload = json.dumps({
    "contents": [{"parts": [{"text": "Generate a simple image of a black crow"}]}],
    "generationConfig": {"responseModalities": ["image", "text"]}
}).encode()

imagen_payload = json.dumps({
    "instances": [{"prompt": "A simple image of a black crow"}],
    "parameters": {"sampleCount": 1}
}).encode()

for model in MODELS:
    is_imagen = model.startswith("imagen")
    url = f"{BASE}/{model}:{'predict' if is_imagen else 'generateContent'}?key={API_KEY}"
    payload = imagen_payload if is_imagen else prompt_payload

    try:
        req = urllib.request.Request(url, data=payload, headers={"Content-Type": "application/json"})
        resp = urllib.request.urlopen(req, timeout=30)
        data = json.loads(resp.read())

        if is_imagen:
            if "predictions" in data:
                print(f"  SUCCESS  {model} - got image prediction!")
            else:
                print(f"  ???      {model} - unexpected response: {str(data)[:100]}")
        else:
            parts = data.get("candidates", [{}])[0].get("content", {}).get("parts", [])
            has_image = any("inlineData" in p for p in parts)
            if has_image:
                size = len([p for p in parts if "inlineData" in p][0]["inlineData"]["data"])
                print(f"  SUCCESS  {model} - got image! ~{size // 1024}KB")
            else:
                text = next((p["text"] for p in parts if "text" in p), "no text")
                print(f"  TEXT OK  {model} - responded but text only: {text[:80]}")

    except urllib.error.HTTPError as e:
        body = e.read().decode()
        try:
            err = json.loads(body)["error"]
            msg = err.get("message", "")[:100]
            code = err.get("code", e.code)
        except Exception:
            msg = body[:100]
            code = e.code
        print(f"  FAIL({code}) {model} - {msg}")
    except Exception as e:
        print(f"  ERROR    {model} - {e}")

