pub fn load_config() -> Result<Config> {
    let config_path = Path::new("CrowConfig.toml");

    if config_path.exists() {
        let config_content =
            fs::read_to_string(config_path).context("Failed to read CrowConfig.toml")?;

        // Pre-process the config content to make keys case-insensitive
        let processed_content = preprocess_config_content(&config_content);

        let config: Config =
            toml::from_str(&processed_content).context("Failed to parse CrowConfig.toml")?;

        return Ok(config);
    }

    Err(anyhow::anyhow!(
        "Configuration file CrowConfig.toml not found"
    ))
}

