                        );

                        // Wait for the specified time plus a small buffer
                        tokio::time::sleep(Duration::from_secs(RETRY_DELAY)).await;
                        continue; // Try again after waiting
                    }

                    // For daily limit or any other error, just return the error
                    return Err(e);
                }
            }
        }
    }

